tasks.solution:
#include <iostream>

int main() {
    int n;
    if (!(std::cin >> n)) return 0;

    // Factorial must start at 1 because 0! = 1 
    // and multiplying by 0 would result in 0.
    long long factorial = 1;

    // The loop must include n (i <= n) to multiply the last digit.
    // If n is 0, the loop condition (1 <= 0) is false, and it correctly returns 1.
    for (int i = 1; i <= n; i++) {
        factorial *= i;
    }

    std::cout << factorial << std::endl;

    return 0;
}
